import sys
from pathlib import Path


def main():
    packages_dir = Path("./packages")

    if not packages_dir.exists() or not packages_dir.is_dir():
        sys.exit(1)

    for pkg in packages_dir.iterdir():
        if not pkg.is_dir():
            continue

        req_file = pkg / "requirements.txt"
        deps: list[str] = []
        if req_file.exists():
            with open(req_file, "r") as f:
                deps = [
                    line.strip()
                    for line in f
                    if line.strip()
                    and (not line.strip().startswith(("#", "-")))
                ]

        deps_str = "".join([f'    "{d}",\n' for d in deps])
        toml_content = f"""[build-system]
requires = ["setuptools>=61.0.0", "wheel"]
build-backend = "setuptools.build_meta"

[project]
name = "{pkg.name}"
version = "0.1.0"
requires-python = ">=3.10"
dependencies = [
{deps_str}]

[tool.setuptools]
package-dir = {{"" = "."}}
"""
        (pkg / "pyproject.toml").write_text(toml_content)


if __name__ == "__main__":
    main()
